import{_ as t,o,c as a,ae as i}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Journeys: Desktop Banners","description":"","frontmatter":{"title":"Journeys: Desktop Banners","slug":"desktop-journeys"},"headers":[],"relativePath":"marketer-hub/desktop-journeys.md","filePath":"marketer-hub/desktop-journeys.md"}'),n={name:"marketer-hub/desktop-journeys.md"};function r(s,e,l,u,d,c){return o(),a("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Journeys: Desktop Banners allow you to easily create beautiful views that direct users of your brand to your mobile app when viewing your website on a desktop. Similar to Branch&#39;s web-to-app Journeys, Journeys: Desktop Banners can be configured based on specific targeting criteria, scheduling, and more! Users will be greeted with a customized interstitial on your website with a QR code that they can use to scan with their mobile device to get to your app.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>To implement Journeys: Desktop Banners, you need to have completed the following:</p><ul><li><p>Integrate the <a href="./native-sdks-overview.html">Branch SDK</a> into your app and configure deep link routing and attribution before implementing Journeys.</p><ul><li>Journeys uses your alternate domain for iOS Universal Links and Android App Links. Make sure you include your <code>xxxx-alternate.app.link</code> domain in your Associated Domains. If you use a custom domain or subdomain for your Branch Links, you should instead add entries for <code>applinks:[mycustomdomainorsubdomain]</code> and <code>XXXX-alternate.app.link</code>.</li></ul></li><li><p>Add the latest version of the <a href="./web-sdk-overview.html">Branch Web SDK</a> to your site.</p></li></ul><h2 id="_1-select-audience" tabindex="-1">1. Select Audience <a class="header-anchor" href="#_1-select-audience" aria-label="Permalink to &quot;1. Select Audience&quot;">​</a></h2><p>Start by clicking the blue <strong>Create</strong> button on the top right of any page on the Branch Dashboard then select <strong>Journey</strong> or by clicking <strong>Create a New Journey</strong> when on the Journeys page.</p><p>Customize the audience that will see your Journey by completing the following fields:</p><ol><li><p><strong>Name Your Journey</strong>: This name is how your Journey will appear in the dashboard view (it will never display to your users). Try to stick to a naming convention so that you can easily find Journeys later. For example Date - Template - OS - Target.</p></li><li><p><strong>What campaign is it part of?</strong>: Campaign will automatically populate to match the Name of the Journey.</p></li><li><p><strong>What channel is it part of?</strong>: Channel is not commonly used but will help you analyze your Journey’s later.</p></li><li><p><strong>Select the audience you want to target</strong>: Desktop</p></li><li><p><strong>This Journey will show if user</strong>: Using the following options add additional user targeting filters.</p><table tabindex="0"><thead><tr><th>Filter</th><th>Description</th></tr></thead><tbody><tr><td>Is located</td><td>Use this filter to target (or exclude) users viewing your website in different regions. You can target by country, state/province, or even by city.</td></tr><tr><td>Is viewing a page url</td><td>You can define which subsets of your website the Journey will appear in. For example, maybe you have a page <code>yoursite.com/settings</code> and <code>yoursite.com/products/1234</code>. You could fill in products here so only users visiting a URL with that substring present would see the Journey.</td></tr><tr><td>Came directly from a url</td><td>You can target a user based on the last touchpoint before they entered your website. For example, if you want to target users that found you through Google Search, you can select “whose domain matches” and fill in “google.com”.</td></tr></tbody></table></li></ol><div class="info custom-block"><p class="custom-block-title">Tips on Filtering</p><ul><li><p>Using multiple filters creates an “and” condition. Meaning, this Journey will only show if all of the conditions are true.</p></li><li><p>You may add additional options for each filter</p><ul><li>ex. Adding different URLs for the exactly matching clause.</li></ul></li><li><p>For URL filters, multiple URL entries creates an “or” condition. In other words, the journey will show if a user is visiting either URL A or B.</p></li><li><p>If your web page ends with a &quot;?&quot;, the question mark character will be treated as an optional expression quantifier for the <strong>&quot;viewing a page URL starting with&quot;</strong> filter. For example, when you set &quot;yoursite.com/?&quot; for this filter, the Journey will appear on &quot;yoursite.com/?&quot;, &quot;yoursite.com/settings&quot; or &quot;yoursite.com/&quot;.</p></li><li><p>For certain filters (ex. <em>is viewing page url exactly matching...</em>), you can paste multiple values by clicking the <strong>Edit All</strong> button. This will effectively make that filter meet OR condition.</p></li></ul><p>You can also view examples audience suggestions <a href="./example-journeys.html">here</a>.</p></div><ol start="6"><li>Click <strong>Save and Continue</strong> when you&#39;re ready to move on to the next phase.</li></ol><h2 id="_2-configure-creative" tabindex="-1">2. Configure Creative <a class="header-anchor" href="#_2-configure-creative" aria-label="Permalink to &quot;2. Configure Creative&quot;">​</a></h2><p>In this phase, you will design the creative your audience will see, or add multiple view variations to A/B test the experience across your audience. To do this:</p><ol><li><strong>Add Variation</strong>: This feature allows you to run A/B test by designing multiple templates and assigning a percentage (total must equal to 100%) of your audience to each one to compare Journey performance. This will allow for rapid iteration as you track performance data. Click the <strong>Add Variation +</strong> button to add a new Journey banner/interstitial, and use the percentage fields to control the ratio of your audience that will see each variation.</li></ol><p>.png)</p><ol start="2"><li>Click <strong>Select Creative</strong> to start designing your banner/interstitial. You will be taken to the Templates page to select a template. Click the <strong>Use</strong> button on the template you want to work with.</li></ol><h3 id="wysiwyg" tabindex="-1">WYSIWYG <a class="header-anchor" href="#wysiwyg" aria-label="Permalink to &quot;WYSIWYG&quot;">​</a></h3><p>You must first name your creative in the <strong>View Name</strong> field. Try to stick to a naming convention so that you can easily find it later. Branch uses a <em>What You See Is What You Get</em> (WYSIWYG) editor to make customization easy. In the preview window, you can click the element you would like to customize (Title, Description, <a href="./journeys-image-recommendations.html">Background Image</a>, etc.).</p><h4 id="editing-qr-code" tabindex="-1">Editing QR Code <a class="header-anchor" href="#editing-qr-code" aria-label="Permalink to &quot;Editing QR Code&quot;">​</a></h4><p>Click on the QR code in the WYSIWYG Editor to configure how the QR code looks for your Journeys. You can adjust the following elements of the QR code:</p><ul><li>Finder Style</li><li>Code Pattern</li><li>Color (Code, Background, and Finder)</li><li>Center Logo</li></ul><h3 id="advanced-ui-editor" tabindex="-1">Advanced UI Editor <a class="header-anchor" href="#advanced-ui-editor" aria-label="Permalink to &quot;Advanced UI Editor&quot;">​</a></h3><p>For more detailed tweaks, use the <strong>CSS Editor, HTML Editor, and Page Placement</strong> tabs to customize your creative to match your brand guidelines.</p><div class="info custom-block"><p class="custom-block-title">Advanced UI Configuration</p><p>We have a detailed guide on advanced UI configuration <a href="./advanced-journeys-ui-html-css.html">here</a>.</p></div><h3 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h3><p>You can add additional tags and deep linking data on the <strong>Configuration</strong> tab.</p><ul><li>Tags: Additional tags you can add to your Journeys campaign to be used for reporting on the Branch Dashboard or exports.</li><li>Deep Link Data: These are key/value pairs that will appear in your mobile app that can be used for things like deep linking, tracking, etc.</li></ul><div class="info custom-block"><p class="custom-block-title">Advanced Journeys Configuration</p><p>We have a detailed guide on utilizing deep link data <a href="./advanced-journeys-configuration.html">here</a>.</p></div><h3 id="dismissal-settings" tabindex="-1">Dismissal Settings <a class="header-anchor" href="#dismissal-settings" aria-label="Permalink to &quot;Dismissal Settings&quot;">​</a></h3><p>You can adjust the Journeys behavior when the creative is dismissed on the <strong>Dismissal Settings</strong> tab.</p><table tabindex="0"><thead><tr><th>Customization</th><th>Description</th></tr></thead><tbody><tr><td>Dismissal Behavior</td><td>Choose what happens when a user dismisses a Journey. “Close Journey” will simply cause the Journey to close upon being dismissed; “Redirect to a web page” will cause the Journey to close and redirect to the webpage of your choice.</td></tr><tr><td>Dismissal Period</td><td>Use the dropdown to choose how long the Journey should be dismissed for. Next, decide whether dismissing this Journey should cause only this Journey or all Journeys to be dismissed for the chosen period.</td></tr></tbody></table><p>Click <strong>Save &amp; Close</strong> when you’re done customizing your creative.</p><p>You will be brought to the Configure Creatives step. You will see the name of the creative you created. You can create and edit another variation, or click <strong>Save and Continue</strong>.</p><h2 id="_3-validate-test" tabindex="-1">3. Validate &amp; Test <a class="header-anchor" href="#_3-validate-test" aria-label="Permalink to &quot;3. Validate &amp; Test&quot;">​</a></h2><p>In the<strong>Validate &amp; Test</strong> section, you should have green checkmarks that indicate if everything is set up properly. If you see any errors, go back to that step to complete the configuration. You can access a list of the errors and what they mean under <a href="./troubleshoot-journey-app-banners.html">Troubleshooting</a>.</p><p>If you have multiple variations, you can preview them by using the dropdown menu.</p><h3 id="scheduling" tabindex="-1">Scheduling <a class="header-anchor" href="#scheduling" aria-label="Permalink to &quot;Scheduling&quot;">​</a></h3><p>When you’re ready to start running your Journey, click the <strong>Schedule</strong> button. A <strong>Schedule</strong> box will appear, where you can configure the following:</p><ul><li>Start/Stop Time and Date</li><li>Repeat Settings (Daily/Weekly)</li><li>Time Zone</li></ul><p>.png &quot;Screen Shot 2021-07-12 at 10.49.21 AM.png&quot;)</p><p>If you’re ready to start running your Journey now, click <strong>Start Journey</strong>. Otherwise, click <strong>Save &amp; Close</strong> to come back and start it later.</p>',41)])])}const g=t(n,[["render",r]]);export{p as __pageData,g as default};
